const express = require('express');
const multer = require('multer');
const xml2js = require('xml2js');
const fs = require('fs');
const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload-xml', upload.single('file'), (req, res) => {
  const filePath = req.file.path;
  fs.readFile(filePath, 'utf8', (err, data) => {
    if (err) return res.status(500).send('File read failed');
    
    xml2js.parseString(data, { normalizeTags: true, trim: true, async: false }, (err, result) => {
      if (err) return res.status(400).send('Invalid XML');
      
      extractConfiguration(result)
        .then((config) => res.json({ status: 'success', config }))
        .catch((error) => res.status(500).send(error.message));
    });
  });
});

async function extractConfiguration(xmlObject) {
  // Implement logic to extract specific configuration data from xmlObject
  // This is a placeholder implementation:
  let config = {};
  if (xmlObject && xmlObject.configuration) {
    config = {
      settings: xmlObject.configuration.settings[0],
      details: xmlObject.configuration.details[0]
    };
  }
  return config;
}

app.listen(3000, () => console.log('Server running on port 3000'));